const rawText = $input.first().json.output || '';
const cleanText = rawText.replace(/^```[\w]*\n?/m, '').replace(/\n?```$/m, '').trim();
const chatId  = $input.first().json.chatId;

// Ambil hanya Tier 1 sections dari output LLM
// Potong sebelum Tier 2 marker
const tier2Markers = ['👥 MANAJEMEN', '💰 PENGGUNAAN DANA', '🏛️ PEMEGANG SAHAM', '⚠️ RISIKO UTAMA'];
let shortText = cleanText;
let cutIndex = shortText.length;

for (const marker of tier2Markers) {
  const idx = shortText.indexOf(marker);
  if (idx > 0 && idx < cutIndex) cutIndex = idx;
}

shortText = shortText.substring(0, cutIndex).trim();

// Trim ke maks 3800 chars untuk satu pesan
if (shortText.length > 3800) {
  shortText = shortText.substring(0, 3780) + '\n<i>... (ringkasan dipotong)</i>';_
}
// Close any unclosed <b> and <i> tags after trimming
const bOpen = (shortText.match(/<b>/g) || []).length;
const bClose = (shortText.match(/<\/b>/g) || []).length;
const iOpen = (shortText.match(/<i>/g) || []).length;
const iClose = (shortText.match(/<\/i>/g) || []).length;
for (let n = 0; n < bOpen - bClose; n++) shortText += '</b>';
for (let n = 0; n < iOpen - iClose; n++) shortText += '</i>';

// Tambahkan hint chatbot di bawah
const hint = `\n\n━━━━━━━━━━━━━━━━━━━━
💬 <b>Punya pertanyaan lebih lanjut?</b>
Ketik langsung pertanyaanmu, misalnya:
<i>"Apa rencana penggunaan dana IPO ini?"</i>
<i>"Siapa pemegang saham terbesarnya?"</i>
<i>"Apa saja risiko utama perusahaan ini?"</i>`;

// Fix nested/unclosed <b> tags by ensuring no nested same tags


return [{
  json: {
    shortText: shortText + hint,
    chatId
  }
}];

const raw = $input.first().json.output || '';
const fileName = $input.first().json.fileName || '';
const date = new Date().toISOString().split('T')[0];

// Simple field extraction from the LLM output text
// Extract text after bold label patterns
function extract(text, label) {
  const patterns = [
    new RegExp(`${label}[:\\s]+([^\\n]+)`, 'i'),
    new RegExp(`•\\s*${label}[:\\s]+([^\\n]+)`, 'i'),
  ];
  for (const p of patterns) {
    const m = text.match(p);
    if (m && m[1]) return m[1].replace(/<[^>]*>/g, '').trim();
  }
  return '';
}

// Extract sections
const namaEmiten    = extract(raw, 'Nama emiten') || extract(raw, 'Nama');
const bidangUsaha   = extract(raw, 'Bidang usaha');
const sektor        = extract(raw, 'Sektor');
const kotaProvinsi  = extract(raw, 'Kota');
const status        = extract(raw, 'Status');
const jmlSaham      = extract(raw, 'Jumlah saham');
const harga         = extract(raw, 'Harga penawaran');
const nilaiNominal  = extract(raw, 'Nilai nominal');
const persPublik    = extract(raw, 'Persentase');
const totalDana     = extract(raw, 'Total dana');
const tglEfektif    = extract(raw, 'Tanggal efektif') || extract(raw, 'efektif');
const penawaran     = extract(raw, 'Masa penawaran');
const tglCatat      = extract(raw, 'pencatatan di BEI') || extract(raw, 'pencatatan');
const underwriter   = extract(raw, 'Penjamin Pelaksana') || extract(raw, 'underwriter');
const auditor       = extract(raw, 'KAP') || extract(raw, 'Auditor');
const bae           = extract(raw, 'BAE');
const konsHukum     = extract(raw, 'Konsultan Hukum');
const dirut         = extract(raw, 'Direktur Utama');
const komut         = extract(raw, 'Komisaris Utama');

return [{
  json: {
    tanggal: date,
    file: fileName,
    nama_emiten: namaEmiten,
    bidang_usaha: bidangUsaha,
    sektor: sektor,
    kota_provinsi: kotaProvinsi,
    status_pmdn_pma: status,
    jumlah_saham: jmlSaham,
    harga_penawaran: harga,
    nilai_nominal: nilaiNominal,
    persen_publik: persPublik,
    total_dana: totalDana,
    tgl_efektif: tglEfektif,
    masa_penawaran: penawaran,
    tgl_pencatatan: tglCatat,
    underwriter: underwriter,
    auditor: auditor,
    bae: bae,
    konsultan_hukum: konsHukum,
    direktur_utama: dirut,
    komisaris_utama: komut
  }
}];

const rawText = $input.first().json.output || '';
const fileName = $input.first().json.fileName || 'prospektus.pdf';
const date      = new Date().toLocaleDateString('id-ID', {day:'2-digit', month:'long', year:'numeric'});

// Strip HTML tags for plain text Google Doc
const plainText = rawText
  .replace(/<b>/g, '').replace(/<\/b>/g, '')
  .replace(/<i>/g, '').replace(/<\/i>/g, '')
  .replace(/<code>/g, '').replace(/<\/code>/g, '')
  .replace(/<blockquote>/g, '').replace(/<\/blockquote>/g, '')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>');

const header = `EXECUTIVE SUMMARY – IPO INTELLIGENCE SYSTEM\nFile: ${fileName}\nTanggal Ekstraksi: ${date}\n${'='.repeat(50)}\n\n`;

const content = header + plainText;

// Generate safe filename
const safeName = fileName.replace('.pdf', '').replace(/[^a-zA-Z0-9\s]/g, '').trim();
const docName = `IPO Summary – ${safeName} (${date}).txt`;

// Convert text content to binary for Google Drive upload
const binaryData = Buffer.from(content, 'utf8').toString('base64');

return [{
  json: {
    content,
    docName,
    fileName
  },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'text/plain',
      fileName: docName,
      fileExtension: 'txt'
    }
  }
}];

const docData = $input.first().json;
const chatId = $('Telegram Trigger').first().json.message.chat.id;
const msg = $('Telegram Trigger').first().json;
const text = msg.message?.text || '';
const cb = msg.callback_query?.data || '';
let question = text || cb || '';

// Strip /tanya prefix
if (question.startsWith('/tanya')) {
  question = question.replace('/tanya', '').trim();
}

// No document
if (!docData || !docData.filename) {
  return [{
    json: {
      chatId,
      noDoc: true,
      answer: `Belum ada prospektus yang diupload.

Silakan kirim /dokumen dan upload file PDF prospektus terlebih dahulu.`
    }
  }];
}

// Document exists but content empty
if (!docData.content || docData.content.trim() === '') {
  return [{
    json: {
      chatId,
      noDoc: true,
      answer: `Gagal membaca isi dokumen ${docData.filename}.

Kemungkinan file PDF tidak bisa diekstrak teksnya (misal: PDF scan/gambar). Coba upload ulang dokumen dalam format PDF yang bisa di-copy teksnya.`
    }
  }];
}

const docText = docData.content;
const filename = docData.filename || 'prospektus';

// Trim if too long
const maxChars = 80000;
const trimmed = docText.length > maxChars
  ? docText.substring(0, maxChars) + `

[...dokumen dipotong karena terlalu panjang]`
  : docText;

return [{
  json: {
    chatId,
    noDoc: false,
    filename,
    question,
    systemPrompt: `Kamu adalah asisten analisis prospektus IPO Indonesia.
WAJIB jawab dalam Bahasa Indonesia yang jelas dan formal.
Jawaban SINGKAT: 3-6 bullet atau 3-5 kalimat, maksimal 1500 karakter.
Jika informasi tidak ada di dokumen, katakan jelas bahwa tidak tersedia di prospektus ini.
Format jawaban menggunakan Telegram HTML: <b>bold</b>, <i>italic</i>.

PENTING - VALIDASI KONTEKS:
Nama perusahaan dalam prospektus ini adalah sesuai isi dokumen. Jika user menyebut nama perusahaan yang TIDAK cocok dengan isi dokumen, WAJIB sampaikan: "Dokumen yang sedang dimuat adalah prospektus <b>[nama di dokumen]</b>, bukan perusahaan yang Anda sebutkan. Berikut jawaban berdasarkan dokumen yang tersedia:"
Lanjutkan menjawab dari dokumen yang ada setelahnya.`,
    userMessage: `Dokumen prospektus: ${filename}

${trimmed}

--
Pertanyaan: ${question}`
  }
}];

const prompt = $('Build QA Prompt').first().json;
const answer = $input.first().json.output?.[0]?.content?.[0]?.text || '';
const now = new Date().toISOString();

return [{
  json: {
    timestamp: now,
    chat_id: prompt.chatId || '',
    filename: prompt.filename || '',
    question: prompt.question || '',
    answer
  }
}];
